sql:
SELECT offense_description
FROM offenses
WHERE id = 1;

SELECT COUNT(DISTINCT individual_id) 
FROM program_attendances 
WHERE program_completion_status = 'Completed';

SELECT mental_health_condition, COUNT(DISTINCT individual_id) AS total_individuals
FROM mental_health
GROUP BY mental_health_condition;

SELECT COUNT(DISTINCT individual_id) AS unique_recidivists
FROM employment_status
WHERE recidivism_within_3years = 1;

external_knowledge:
- 'Blossomed into full productivity' refers to individuals who have successfully completed a rehabilitation program and are employed for at least 50% of the days since their release;
- 'Program completion' indicates that the individual has successfully finished the rehabilitation program;
- 'Post-release days' refers to the days since the individual was released from a program or institution.

sql:
SELECT COUNT(DISTINCT v.individual_id) AS count_individuals
FROM violations v
INNER JOIN health_records h ON v.individual_id = h.individual_id;

external_knowledge:
- 'Encounters with the law' refer to the total number of violations;
- 'Time spent in prison' is the sum of prison terms in years;
- 'Participation in rehabilitation programs' is the total number of program attendances and distinct rehabilitation programs;
- 'Health and mental health issues' include the total number of health records and mental health records.

sql:
SELECT COUNT(*)
FROM prison_terms
WHERE offense_id = 1;

SELECT COUNT(id) 
FROM mental_health 
WHERE mental_health_condition = 'Depression';

SELECT COUNT(DISTINCT individual_id) AS TotalConvictions
FROM prison_terms
WHERE imprisonment_date BETWEEN '2018-01-01' AND '2020-12-31';

external_knowledge:
- 'Completed' in `program_completion_status` indicates the individual has successfully finished the program;
- 'recidivism_within_3years = 0' indicates the individual has not been reconvicted within 3 years of release;
- `percent_days_employed` is a measure of the percentage of days the individual has been employed since their release.

- 'Returned to the shadows of their past' refers to individuals who have been recidivist within 3 years of release;
- 'Bearing the weight of hypertension' refers to individuals with a medical condition of 'Hypertension';
- 'Found the light of employment for more than 70% of their days' refers to the `percent_days_employed` being greater than 70%;
- 'More than one step forward' refers to the condition `COUNT(e.individual_id) > 1`, indicating that the individual has more than one record in the dataset.

- 'Multiple violations' refers to more than two violations;
- 'Last decade' refers to the period between 2010 and 2020;
- 'Employed more than half the time' means the percentage of days employed is greater than 50%;
- 'Master's Degree' is the highest level of education completed by the individual.

sql:
SELECT program_name
FROM rehabilitation_programs
WHERE program_description LIKE '%Substance Abuse%';

external_knowledge:
- 'Successful Rehabilitation' is defined as attending more than 2 programs with a completion rate of 80% or higher;
- 'Stable Employment' is defined as being employed 80% or more of the days, holding 2 or fewer jobs per year, and not recidivating within 3 years of release;
- 'Serving a sentence of at least 5 years' is calculated by adding the number of years and converting the months to years.

sql:
SELECT DISTINCT highest_education_level
FROM education
ORDER BY highest_education_level ASC;

external_knowledge:
- 'Walked the long road of rehabilitation' refers to individuals who have attended a rehabilitation program;
- 'Found at least half of their days post-release under the sun of employment' refers to a percentage of days employed since release greater than 50%;
- 'Spent in the shadows of prison' refers to the total number of years served in prison.

- "phoenixes that rose from the ashes" refers to individuals who were released from prison and subsequently found employment;
- "dawn of 2018" refers to the date January 1, 2018;
- "fall back into the cycle of crime" refers to individuals who have been recidivist within 3 years of their release.

- "Embarked on the path of rehabilitation" refers to attending rehabilitation programs;
- "Found their way out of the prison's shadow" refers to being released from prison;
- "Within the last three years" refers to the time period from the current date back three years.

- "latest mental health records" refers to the most recent mental health condition, treatment status, and medication for each individual;
- "total number of times they've been confined" refers to the total number of prison terms;
- "average days they've spent in the sunlight of employment" refers to the average percentage of days employed since release;
- "number of times they've attended the watering hole of rehabilitation programs" refers to the total number of rehabilitation program attendances.
